CREATE TABLE scheduled_reports (id VARCHAR(36) PRIMARY KEY, college_id VARCHAR(64) NOT NULL, name VARCHAR(160) NOT NULL, report_type VARCHAR(32) NOT NULL, cron_expression VARCHAR(80) NOT NULL, export_format VARCHAR(16) NOT NULL DEFAULT 'PDF', recipients TEXT NOT NULL DEFAULT '[]', filters_json TEXT NOT NULL DEFAULT '{}', status VARCHAR(16) NOT NULL DEFAULT 'ACTIVE', created_by VARCHAR(64) NOT NULL, last_run_at TIMESTAMP, created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT uq_scheduled_report_name_college UNIQUE (college_id, name));
CREATE INDEX ix_scheduled_reports_college_type_status ON scheduled_reports (college_id, report_type, status);
